### Project Setup
1. **Include SDL2**:
    - Set include paths and linker options for SDL2 headers and libraries.

2. **Initialization and Setup**:
    ```c
    #include <SDL2/SDL.h>
    #include <SDL2/SDL_image.h>
    #include <stdbool.h>
    #include <stdlib.h>
    #include <time.h>

    const int SCREEN_WIDTH = 640;
    const int SCREEN_HEIGHT = 480;
    const int GRID_SIZE = 20;

    typedef struct { int x, y; } Point;
    typedef enum { UP, DOWN, LEFT, RIGHT } Direction;
    typedef struct { Point* body; int length; Direction direction; } Snake;

    SDL_Window* window = NULL;
    SDL_Renderer* renderer = NULL;
    SDL_Texture* grassTexture = NULL;
    SDL_Texture* snakeHeadTexture = NULL;
    SDL_Texture* snakeBodyTexture = NULL;
    SDL_Texture* foodTexture = NULL;

    Snake snake;
    Point food;

    bool init();
    void loadMedia();
    void close();
    void initGame();
    void updateGameLogic();
    void render();
    void handleInput(SDL_Event* e);
    ```

3. **Initialize SDL and Create Window**:
    ```c
    bool init() {
        if (SDL_Init(SDL_INIT_VIDEO) < 0) return false;
        window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, SCREEN_WIDTH, SCREEN_HEIGHT, SDL_WINDOW_SHOWN);
        if (!window) return false;
        renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
        if (!renderer) return false;
        if (!(IMG_Init(IMG_INIT_PNG) & IMG_INIT_PNG)) return false;
        return true;
    }
    ```

4. **Load Images**:
    ```c
    void loadMedia() {
        grassTexture = IMG_LoadTexture(renderer, "grass.png");
        snakeHeadTexture = IMG_LoadTexture(renderer, "snake_head.png");
        snakeBodyTexture = IMG_LoadTexture(renderer, "snake_body.png");
        foodTexture = IMG_LoadTexture(renderer, "food.png");
        if (!grassTexture || !snakeHeadTexture || !snakeBodyTexture || !foodTexture) exit(1);
    }
    ```

5. **Initialize Game State**:
    ```c
    void initGame() {
        snake.length = 1;
        snake.body = malloc(sizeof(Point) * 100);
        snake.body[0].x = SCREEN_WIDTH / 2 / GRID_SIZE;
        snake.body[0].y = SCREEN_HEIGHT / 2 / GRID_SIZE;
        snake.direction = RIGHT;
        srand(time(NULL));
        food.x = rand() % (SCREEN_WIDTH / GRID_SIZE);
        food.y = rand() % (SCREEN_HEIGHT / GRID_SIZE);
    }
    ```

6. **Game Logic**:
    ```c
    void updateGameLogic() {
        for (int i = snake.length - 1; i > 0; i--) snake.body[i] = snake.body[i - 1];
        switch (snake.direction) {
            case UP: snake.body[0].y--; break;
            case DOWN: snake.body[0].y++; break;
            case LEFT: snake.body[0].x--; break;
            case RIGHT: snake.body[0].x++; break;
        }
        if (snake.body[0].x == food.x && snake.body[0].y == food.y) {
            snake.length++;
            snake.body = realloc(snake.body, snake.length * sizeof(Point));
            food.x = rand() % (SCREEN_WIDTH / GRID_SIZE);
            food.y = rand() % (SCREEN_HEIGHT / GRID_SIZE);
        }
        if (snake.body[0].x < 0 || snake.body[0].x >= SCREEN_WIDTH / GRID_SIZE || snake.body[0].y < 0 || snake.body[0].y >= SCREEN_HEIGHT / GRID_SIZE) exit(0);
        for (int i = 1; i < snake.length; i++) if (snake.body[0].x == snake.body[i].x && snake.body[0].y == snake.body[i].y) exit(0);
    }
    ```

7. **Rendering**:
    ```c
    void render() {
        SDL_SetRenderDrawColor(renderer, 0xFF, 0xFF, 0xFF, 0xFF);
        SDL_RenderClear(renderer);
        SDL_Rect grassRect = { 0, 0, GRID_SIZE, GRID_SIZE };
        for (int y = 0; y < SCREEN_HEIGHT / GRID_SIZE; ++y) {
            for (int x = 0; x < SCREEN_WIDTH / GRID_SIZE; ++x) {
                grassRect.x = x * GRID_SIZE;
                grassRect.y = y * GRID_SIZE;
                SDL_RenderCopy(renderer, grassTexture, NULL, &grassRect);
            }
        }
        SDL_Rect snakeRect = { 0, 0, GRID_SIZE, GRID_SIZE };
        for (int i = 0; i < snake.length; i++) {
            snakeRect.x = snake.body[i].x * GRID_SIZE;
            snakeRect.y = snake.body[i].y * GRID_SIZE;
            SDL_RenderCopy(renderer, (i == 0 ? snakeHeadTexture : snakeBodyTexture), NULL, &snakeRect);
        }
        SDL_Rect foodRect = { food.x * GRID_SIZE, food.y * GRID_SIZE, GRID_SIZE, GRID_SIZE };
        SDL_RenderCopy(renderer, foodTexture, NULL, &foodRect);
        SDL_RenderPresent(renderer);
    }
    ```

8. **Handling Input**:
    ```c
    void handleInput(SDL_Event* e) {
        if (e->type == SDL_KEYDOWN) {
            switch (e->key.keysym.sym) {
                case SDLK_UP: if (snake.direction != DOWN) snake.direction = UP; break;
                case SDLK_DOWN: if (snake.direction != UP) snake.direction = DOWN; break;
                case SDLK_LEFT: if (snake.direction != RIGHT) snake.direction = LEFT; break;
                case SDLK_RIGHT: if (snake.direction != LEFT) snake.direction = RIGHT; break;
            }
        }
    }
    ```

9. **Main Game Loop**:
    ```c
    int main(int argc, char* args[]) {
        if (!init()) return 1;
        loadMedia();
        initGame();
        bool quit = false;
        SDL_Event e;
        Uint32 lastUpdate = SDL_GetTicks();
        const int FPS = 10;
        const int frameDelay = 1000 / FPS;
        while (!quit) {
            Uint32 currentTicks = SDL_GetTicks();
            Uint32 frameStart = SDL_GetTicks();
            while (SDL_PollEvent(&e) != 0) {
                if (e.type == SDL_QUIT) quit = true;
                else handleInput(&e);
            }
            if (currentTicks - lastUpdate >= frameDelay) {
                updateGameLogic();
                lastUpdate = currentTicks;
            }
            render();
            int frameTime = SDL_GetTicks() - frameStart;
            if (frameDelay > frameTime) SDL_Delay(frameDelay - frameTime);
        }
        close();
        return 0;
    }
    ```

10. **Cleanup**:
    ```c
    void close() {
        SDL_DestroyTexture(grassTexture);
        SDL_DestroyTexture(snakeHeadTexture);
        SDL_DestroyTexture(snakeBodyTexture);
        SDL_DestroyTexture(foodTexture);
        SDL_DestroyRenderer(renderer);
        SDL_DestroyWindow(window);
        free(snake.body);
        IMG_Quit();
        SDL_Quit();
    }
    ```

